function maxColumnWidth(gridLayout) {
  let maxWidth = 0;
  let gridItems = gridLayout.split(' ');
  let n = gridItems.length / 2;
  for (let i = 0; i < n; i++) {
    maxWidth = Math.max(maxWidth, parseInt(gridItems[i * 2]));
  }
  return maxWidth;
}

