// Solution: Use a greedy algorithm to find the maximum column width based on the grid item widths and the number of columns
function maxColumnWidth(gridLayout) {
  let maxWidth = 0;
  let gridItems = gridLayout.split(' ');
  let n = gridItems.length / 2;
  for (let i = 0; i < n; i++) {
    maxWidth = Math.max(maxWidth, parseInt(gridItems[i * 2 + 1]));
  }
  return maxWidth;
}

